double session_math_add(double arg0, double arg1) {
    session_math_ctx_t* ctx = session_math__require_ctx();
    double ret = 0.0;
    wasm_error_t err;
    wasm_value_t args[2];
    wasm_value_t results[1];

    if (!ctx) return ret;
    args[0] = wasm_f64(arg0);
    args[1] = wasm_f64(arg1);
    err = wasm_call_index(ctx->mod, ctx->idx_add, args, 2, results, 1);
    if (err != WASM_OK) { session_math_capture_runtime_error(ctx, err, NULL); return ret; }
    ret = results[0].of.f64;
    session_math_clear_error(ctx);
    return ret;
}

